module d_flip_flop(
    input       d     ,
    input       obf_clk   ,
    input       reset ,

    output reg  q
);

   // D Flip-Flop with asynchronous reset
   always @(posedge obf_clk or posedge reset) begin
       if (reset) begin
           q <= 1'b0;
       end else begin
           q <= d;
       end
   end

endmodule
